import { test, expect } from '@playwright/test';

test('Amazon.sg search for headphones and validate results', async ({ page }) => {
  // 1. Launch browser and navigate to Amazon.sg
  await page.goto('https://www.amazon.sg');

  // 2. Wait for search input (name="field-keywords")
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible();

  // 3. Enter "headphones"
  await searchInput.fill('headphones');

  // 4. Press Enter
  await searchInput.press('Enter');

  // 5. Wait for search results to load
  const resultsLocator = page.locator('div.s-main-slot div[data-component-type="s-search-result"]');
  await expect(resultsLocator.first()).toBeVisible({ timeout: 10000 });

  // 6. Validate at least one result is displayed
  const resultCount = await resultsLocator.count();
  expect(resultCount).toBeGreaterThan(0);

  // 7. Close browser (handled automatically by Playwright)
});
